css:
@page {
  size: A4; margin: 15mm 20mm 22mm 20mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #1c1c1c; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }
.doc-header { display: block; margin: 0; }

.ex-top { display: flex; align-items: center; justify-content: space-between; }
.ex-brand { display: flex; align-items: center; gap: 3mm; }
.ex-mark { height: 9mm; width: 9mm; display: block; }
.ex-brandname { font-size: 11pt; font-weight: 700; letter-spacing: 0.02em; }
.ex-eyebrow { font-size: 8pt; letter-spacing: 0.22em; text-transform: uppercase; color: #a67c2e; font-weight: 700; }

.ex-rule { height: 1px; background: #1c1c1c; margin: 4mm 0 0; }

.ex-cover { margin: 4mm 0 4mm; }
.ex-title { font-family: 'Georgia', 'Times New Roman', serif; font-size: 22pt; font-weight: 700; line-height: 1.08; letter-spacing: -0.01em; margin: 0; max-width: 150mm; }
.ex-lead { font-size: 9.5pt; line-height: 1.4; color: #4a463e; margin-top: 3mm; max-width: 152mm; }

.ex-meta { display: flex; gap: 6mm; padding: 3mm 0; border-top: 1px solid #e4ded2; border-bottom: 1px solid #e4ded2; margin-bottom: 4.5mm; }
.ex-meta__col { flex: 1 1 0; min-width: 0; }
.ex-meta__col > div { line-height: 1.45; font-size: 9.5pt; }
.ex-label { font-size: 7pt; letter-spacing: 0.16em; text-transform: uppercase; color: #a67c2e; font-weight: 700; margin-bottom: 1.6mm; }
.ex-meta__strong { font-weight: 700; }

.ex-h2 { font-family: 'Georgia', 'Times New Roman', serif; font-size: 13pt; font-weight: 700; margin: 0 0 3mm; }

.ex-items { width: 100%; border-collapse: collapse; margin-bottom: 7mm; }
.ex-items thead th { font-size: 7.5pt; letter-spacing: 0.12em; text-transform: uppercase; color: #8a8478; font-weight: 700; text-align: left; padding: 0 0 2.5mm; border-bottom: 2px solid #a67c2e; }
.ex-items tbody td { padding: 2.3mm 0; border-bottom: 1px solid #e4ded2; vertical-align: top; }
.ex-c-pos { width: 12mm; font-family: 'Georgia', serif; color: #a67c2e; font-size: 11pt; }
.ex-c-qty { width: 24mm; text-align: right; color: #4a463e; }
.ex-c-price { width: 28mm; text-align: right; color: #4a463e; }
.ex-c-total { width: 30mm; text-align: right; font-weight: 700; }
.ex-iname { font-family: 'Georgia', 'Times New Roman', serif; font-size: 11pt; font-weight: 700; display: block; }
.ex-idesc { display: block; color: #6c685e; font-size: 8.5pt; margin-top: 0.8mm; line-height: 1.35; }
thead th.ex-c-qty, thead th.ex-c-price, thead th.ex-c-total { text-align: right; }

.ex-foot { display: flex; justify-content: space-between; gap: 12mm; align-items: flex-start; }
.ex-sign { flex: 1 1 0; }
.ex-note { font-size: 8.5pt; color: #6c685e; line-height: 1.4; margin: 1mm 0 4mm; max-width: 92mm; }
.ex-signline { display: flex; gap: 8mm; }
.ex-sigfield { flex: 1 1 0; }
.ex-sigrule { display: block; border-top: 1px solid #1c1c1c; margin-bottom: 1.5mm; height: 7mm; }
.ex-siglabel { font-size: 8pt; color: #8a8478; }

.ex-totals { flex: 0 0 72mm; background: #1c1c1c; color: #f3efe6; border-radius: 2mm; padding: 5mm; }
.ex-trow { display: flex; justify-content: space-between; gap: 5mm; padding: 1.4mm 0; font-size: 10pt; color: #c9c3b5; }
.ex-trow--grand { margin-top: 2mm; padding-top: 2.5mm; border-top: 1px solid #44403a; font-size: 12pt; font-weight: 700; color: #ffffff; align-items: baseline; }
.ex-trow--grand span:first-child { letter-spacing: -0.01em; }
.ex-trow--grand .num { color: #d8b878; white-space: nowrap; }
.ex-trow__note { margin-top: 1.5mm; font-size: 7.5pt; color: #8a8478; text-align: right; }
